class Solution:
    def sumGame(self, num):
        h = len(num) // 2
        left = num[:h]
        right = num[h:]
        s1 = sum(int(c) for c in left if c != '?')
        s2 = sum(int(c) for c in right if c != '?')
        q1 = left.count('?')
        q2 = right.count('?')
        if (q1 + q2) % 2 == 1:
            return True
        return 9 * (q1 - q2) != 2 * (s2 - s1)

