class Solution:
    def sumGame(self, num):
        h = len(num) // 2
        s1 = q1 = s2 = q2 = 0
        for i, c in enumerate(num):
            if i < h:
                if c == '?':
                    q1 += 1
                else:
                    s1 += int(c)
            else:
                if c == '?':
                    q2 += 1
                else:
                    s2 += int(c)
        if (q1 + q2) % 2 == 1:
            return True
        return 9 * (q1 - q2) != 2 * (s2 - s1)

