var sumGame = function(num) {
    const h = num.length / 2;
    let s1 = 0, q1 = 0, s2 = 0, q2 = 0;
    for (let i = 0; i < num.length; i++) {
        const c = num[i];
        if (i < h) {
            if (c === '?') q1++; else s1 += +c;
        } else {
            if (c === '?') q2++; else s2 += +c;
        }
    }
    if ((q1 + q2) % 2 === 1) return true;
    return 9 * (q1 - q2) !== 2 * (s2 - s1);
};
